// src/pages/Student/index.jsx
import { useState, useEffect, useRef } from "react";
import { T } from "../../assets/styles/theme";
import {
  Btn, Card, Badge, Avatar, Input, Select,
  StatCard, Table, Tabs, ProgressBar, DonutChart,
  PageHeader, ProfileAlert, Modal, calcProfileCompletion,
} from "../../components/UI";
import { DashLayout } from "../../components/Layout";
import { useStudentProfile } from "../../context/StudentProfileContext";
import { StudentForum } from "../Forum";
import {
  updateStudentProfile,
  getStudentCourses, getStudentAssignments, getStudentSubmissions,
  getStudentFees, getStudentNotifications, markStudentNotifRead, markStudentNotifReadAll,
  getStudentAnnouncements,
} from "../../api/auth";

// ── Public department fetch (no token needed) ─────────────────────────────────
async function fetchDepartments() {
  try {
    const res  = await fetch("http://localhost:8080/api/public/departments");
    const body = await res.json().catch(() => ({}));
    return Array.isArray(body.data) ? body.data : [];
  } catch { return []; }
}

// ─── STUDENT OVERVIEW ─────────────────────────────────────────────────────────
export const StudentOverview = ({ onNav }) => {
  const { profile } = useStudentProfile();
  const [courses, setCourses] = useState([]);
  const [fees, setFees]       = useState([]);
  const [notifs, setNotifs]   = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    Promise.all([getStudentCourses(), getStudentFees(), getStudentNotifications()])
      .then(([c, f, n]) => {
        setCourses(Array.isArray(c) ? c : []);
        setFees(Array.isArray(f) ? f : []);
        setNotifs(Array.isArray(n) ? n : []);
      })
      .catch(console.error)
      .finally(() => setLoading(false));
  }, []);

  const pendingFees  = fees.filter(f => f.status === "PENDING" || f.status === "OVERDUE");
  const unreadNotifs = notifs.filter(n => !n.read);

  return (
    <div className="fade-up">
      <PageHeader title="Student Dashboard" subtitle={`Welcome back, ${profile?.name || "Student"}! Here's your progress.`} />
      <div style={{ display: "grid", gridTemplateColumns: "repeat(4,1fr)", gap: 18, marginBottom: 24 }}>
        <StatCard icon="📚" label="Enrolled Courses" value={loading ? "…" : courses.length}      change={`${courses.filter(c => c.status === "ACTIVE").length} active`} color={T.primaryL} />
        <StatCard icon="🏫" label="Department"        value={profile?.department || "—"}           color={T.accentG} />
        <StatCard icon="💳" label="Pending Fees"      value={loading ? "…" : pendingFees.length}   change={pendingFees.length > 0 ? "Action needed" : "All clear"} color={T.accentY} />
        <StatCard icon="🔔" label="Unread Notifs"     value={loading ? "…" : unreadNotifs.length}  color={T.accentR} />
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "2fr 1fr", gap: 20 }}>
        <div>
          {/* Active Courses */}
          <Card style={{ marginBottom: 20 }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
              <div style={{ fontFamily: "Syne", fontWeight: 700, fontSize: 15 }}>Active Courses</div>
              <Btn size="xs" variant="ghost" onClick={() => onNav("courses")}>View All</Btn>
            </div>
            {loading
              ? <div style={{ color: T.muted, textAlign: "center", padding: 16 }}>Loading…</div>
              : courses.length === 0
                ? <div style={{ color: T.muted, textAlign: "center", padding: 16 }}>No courses enrolled yet.</div>
                : <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 14 }}>
                    {courses.slice(0, 4).map(c => (
                      <div key={c.id} style={{ background: T.bg3, borderRadius: 12, overflow: "hidden" }}>
                        <div style={{ height: 80, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 36 }}>📚</div>
                        <div style={{ padding: 12 }}>
                          <div style={{ fontWeight: 700, fontSize: 13, marginBottom: 4 }}>{c.title}</div>
                          <div style={{ fontSize: 11, color: T.muted, marginBottom: 8 }}>{c.teacher?.name || "—"}</div>
                          <Badge type={c.status === "ACTIVE" ? "success" : "warning"}>{c.status}</Badge>
                        </div>
                      </div>
                    ))}
                  </div>
            }
          </Card>

          {/* Fee Status */}
          <Card>
            <div style={{ fontFamily: "Syne", fontWeight: 700, fontSize: 15, marginBottom: 14 }}>Fee Status</div>
            {loading
              ? <div style={{ color: T.muted, textAlign: "center", padding: 16 }}>Loading…</div>
              : fees.length === 0
                ? <div style={{ color: T.muted, padding: 8 }}>No fee records found.</div>
                : fees.slice(0, 4).map(f => (
                  <div key={f.id} style={{ display: "flex", gap: 14, padding: "10px 0", borderBottom: `1px solid rgba(45,33,96,.4)`, alignItems: "center" }}>
                    <div style={{ flex: 1 }}>
                      <div style={{ fontSize: 13, fontWeight: 600 }}>{f.description || "Fee"}</div>
                      <div style={{ fontSize: 11, color: T.muted }}>Due: {f.dueDate || "—"}{f.batch ? ` · ${f.batch.name}` : ""}{f.course ? ` · ${f.course.title}` : ""}</div>
                    </div>
                    <div style={{ fontFamily: "Syne", fontWeight: 800, fontSize: 15, color: T.accent }}>₹{Number(f.amount || 0).toLocaleString("en-IN")}</div>
                    <Badge type={f.status === "PAID" ? "success" : f.status === "OVERDUE" ? "danger" : "warning"}>{f.status}</Badge>
                  </div>
                ))
            }
          </Card>
        </div>

        <div>
          {/* Profile completion donut */}
          <Card style={{ marginBottom: 18, textAlign: "center", padding: 24 }}>
            <div style={{ fontFamily: "Syne", fontWeight: 700, marginBottom: 14 }}>Profile Completion</div>
            {profile && (() => {
              const { pct } = calcProfileCompletion("student", profile);
              return (
                <>
                  <DonutChart pct={pct} color={T.primaryL} label="Complete" />
                  <div style={{ fontSize: 13, color: T.muted, marginTop: 10 }}>
                    {pct < 80 ? "Complete profile to unlock all features" : "Great job!"}
                  </div>
                  {pct < 100 && <Btn variant="warning" size="sm" style={{ marginTop: 12 }} onClick={() => onNav("profile")}>Complete Profile →</Btn>}
                </>
              );
            })()}
          </Card>

          {/* Recent Notifications */}
          <Card>
            <div style={{ fontFamily: "Syne", fontWeight: 700, marginBottom: 14 }}>Notifications</div>
            {loading
              ? <div style={{ color: T.muted, fontSize: 12, padding: 8 }}>Loading…</div>
              : notifs.length === 0
                ? <div style={{ color: T.muted, fontSize: 12, padding: 8 }}>No notifications.</div>
                : notifs.slice(0, 4).map(n => (
                  <div key={n.id} style={{ display: "flex", gap: 10, padding: "8px 0", borderBottom: `1px solid rgba(45,33,96,.3)`, alignItems: "flex-start" }}>
                    <div style={{ width: 7, height: 7, borderRadius: "50%", background: n.read ? T.border : T.primaryL, marginTop: 5, flexShrink: 0 }} />
                    <div>
                      <div style={{ fontSize: 13, fontWeight: n.read ? 500 : 700 }}>{n.title}</div>
                      <div style={{ fontSize: 11, color: T.muted }}>{n.message}</div>
                    </div>
                  </div>
                ))
            }
            {notifs.length > 0 && <Btn size="xs" variant="ghost" style={{ marginTop: 10 }} onClick={() => onNav("notifications")}>View All</Btn>}
          </Card>
        </div>
      </div>
    </div>
  );
};

// ─── STUDENT PROFILE ──────────────────────────────────────────────────────────
// Uses StudentProfileContext so saved data persists when navigating away and back
export const StudentProfile = () => {
  const { profile, updateProfileField } = useStudentProfile();
  const [form, setForm]           = useState(null);
  const [depts, setDepts]         = useState([]);
  const [saving, setSaving]       = useState(false);
  const [uploading, setUploading] = useState(false);
  const fileRef                   = useRef(null);

  // Sync form from context profile whenever profile loads or changes
  // Uses a ref to track if we already initialized so unsaved edits aren't lost
  const initializedRef = useRef(false);

  useEffect(() => {
    // Initialize form from context on first load, or re-sync after a save
    if (profile && !initializedRef.current) {
      initializedRef.current = true;
      setForm({
        name:          profile.name          || "",
        email:         profile.email         || "",
        phone:         profile.phone         || "",
        address:       profile.address       || "",
        department:    profile.department    || "",
        gender:        profile.gender        || "",
        userId:        profile.userId        || "",
        profilePicUrl: profile.profilePicUrl || "",
      });
    }
  }, [profile]);

  // Fetch departments (public, no token)
  useEffect(() => {
    fetchDepartments().then(setDepts).catch(console.error);
  }, []);

  const f = form || {};
  const { pct, missing } = calcProfileCompletion("student", f);

  const handleSave = async () => {
    try {
      setSaving(true);
      await updateStudentProfile({
        name: f.name, phone: f.phone, address: f.address,
        department: f.department, gender: f.gender, profilePicUrl: f.profilePicUrl,
      });
      // Push saved values into context → ProfileAlert banner updates instantly everywhere
      updateProfileField({
        name: f.name, phone: f.phone, address: f.address,
        department: f.department, gender: f.gender, profilePicUrl: f.profilePicUrl,
      });
      alert("Profile updated successfully!");
    } catch (err) { alert("Failed: " + err.message); }
    finally { setSaving(false); }
  };

  const handleFileChange = async (e) => {
    const file = e.target.files[0]; if (!file) return;
    const reader = new FileReader();
    reader.onload = async (ev) => {
      const dataUrl = ev.target.result;
      setForm(prev => ({ ...prev, profilePicUrl: dataUrl }));
      updateProfileField({ profilePicUrl: dataUrl });
      try {
        setUploading(true);
        await updateStudentProfile({ profilePicUrl: dataUrl });
      } catch (err) {
        alert("Photo upload failed: " + err.message);
        setForm(prev => ({ ...prev, profilePicUrl: "" }));
        updateProfileField({ profilePicUrl: "" });
      } finally { setUploading(false); }
    };
    reader.readAsDataURL(file);
    e.target.value = "";
  };

  const handleRemovePhoto = async () => {
    setForm(prev => ({ ...prev, profilePicUrl: "" }));
    updateProfileField({ profilePicUrl: "" });
    await updateStudentProfile({ profilePicUrl: "" }).catch(console.error);
  };

  if (!form) return <div style={{ padding: 32, textAlign: "center", color: T.muted }}>Loading…</div>;

  return (
    <div className="fade-up">
      <PageHeader title="My Profile" />
      <ProfileAlert pct={pct} missing={missing} onComplete={() => fileRef.current?.click()} />
      <input ref={fileRef} type="file" accept="image/*" style={{ display: "none" }} onChange={handleFileChange} />

      <div style={{ display: "grid", gridTemplateColumns: "1fr 2fr", gap: 24 }}>
        {/* Left — avatar card */}
        <Card style={{ textAlign: "center", padding: 32 }}>
          <DonutChart pct={pct} color={T.primaryL} label="Complete" />
          <div style={{ fontSize: 13, fontWeight: 700, color: T.accentY, marginTop: 8 }}>Profile {pct}% Complete</div>

          <div style={{ position: "relative", width: 80, margin: "16px auto 0" }}>
            {f.profilePicUrl ? (
              <div style={{ width: 80, height: 80, borderRadius: "50%", overflow: "hidden", border: `3px solid ${T.primaryL}` }}>
                <img src={f.profilePicUrl} alt="Profile" style={{ width: "100%", height: "100%", objectFit: "cover" }} />
              </div>
            ) : (
              <Avatar name={f.name || "S"} size={80} color={T.accent} />
            )}
            {uploading && (
              <div style={{ position: "absolute", inset: 0, borderRadius: "50%", background: "rgba(0,0,0,0.55)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 20 }}>⏳</div>
            )}
          </div>

          <div style={{ fontFamily: "Syne", fontSize: 18, fontWeight: 800, marginTop: 12 }}>{f.name || "—"}</div>
          <div style={{ fontSize: 13, color: T.muted }}>{f.userId || "—"}</div>
          {f.department && <Badge type="info" style={{ marginTop: 6 }}>{f.department}</Badge>}

          <Btn variant="dark" size="sm" full style={{ marginTop: 16 }} disabled={uploading}
            onClick={() => fileRef.current?.click()}>
            📷 {uploading ? "Uploading…" : f.profilePicUrl ? "Change Photo" : "Upload Photo (Optional)"}
          </Btn>
          {f.profilePicUrl && !uploading && (
            <Btn variant="ghost" size="sm" full style={{ marginTop: 8 }} onClick={handleRemovePhoto}>✕ Remove Photo</Btn>
          )}
        </Card>

        {/* Right — form card */}
        <Card style={{ padding: 28 }}>
          <div style={{ fontFamily: "Syne", fontSize: 17, fontWeight: 800, marginBottom: 20 }}>Update Profile</div>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 14 }}>
            <Input label="Full Name *"   value={f.name}  onChange={e => setForm(p => ({ ...p, name: e.target.value }))} placeholder="Your full name" />
            <Input label="Email Address" value={f.email} onChange={() => {}} style={{ opacity: 0.6, cursor: "not-allowed" }} />
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 14 }}>
            <Input label="Phone Number *" value={f.phone}  onChange={e => setForm(p => ({ ...p, phone: e.target.value }))} placeholder="+91 98765 43210" />
            <Select label="Gender" value={f.gender} onChange={e => setForm(p => ({ ...p, gender: e.target.value }))}
              options={[{ value: "", label: "Select Gender" }, "Male", "Female", "Other"].map(o => typeof o === "string" ? { value: o, label: o } : o)} />
          </div>
          <Select
            label="Department *"
            value={f.department}
            onChange={e => setForm(p => ({ ...p, department: e.target.value }))}
            options={[
              { value: "", label: depts.length === 0 ? "No departments — contact admin" : "-- Select Department --" },
              ...depts.map(d => ({ value: d.name, label: d.name })),
            ]}
          />
          {depts.length === 0 && (
            <div style={{ fontSize: 12, color: T.accentY, marginBottom: 14 }}>
              ⚠️ No departments found. Ask your admin to create departments first.
            </div>
          )}
          <Input label="Address" value={f.address} onChange={e => setForm(p => ({ ...p, address: e.target.value }))} placeholder="Street address, City, Pincode" />
          <Btn variant="primary" size="lg" onClick={handleSave} disabled={saving || uploading}>
            {saving ? "Saving…" : "Save Profile →"}
          </Btn>
        </Card>
      </div>
    </div>
  );
};

// ─── STUDENT COURSES ──────────────────────────────────────────────────────────
export const StudentCourses = () => {
  const [batches, setBatches]         = useState([]);
  const [directCourses, setDirect]    = useState([]); // directly enrolled (no batch)
  const [selected, setSelected]       = useState(null); // selected batch
  const [loading, setLoading]         = useState(true);

  useEffect(() => {
    const { getStudentBatches, getStudentCourses } = require("../../api/auth");
    Promise.all([getStudentBatches(), getStudentCourses()])
      .then(([b, c]) => {
        const batchList = Array.isArray(b) ? b : [];
        setBatches(batchList);
        // Direct courses = from student_courses table (admin direct enrollment)
        // These are separate from batch courses — show ALL of them
        // Backend already returns only direct enrollments in /student/courses
        // that aren't from batches (deduped server-side)
        const batchCourseIds = new Set(batchList.map(bt => bt.course?.id).filter(Boolean));
        const allCourses = Array.isArray(c) ? c : [];
        // Show courses not already shown via batch cards
        const direct = allCourses.filter(course => !batchCourseIds.has(course.id));
        setDirect(direct);
      })
      .catch(console.error)
      .finally(() => setLoading(false));
  }, []);

  const statusColor = { ACTIVE: T.accentG, UPCOMING: T.accentY, COMPLETED: T.muted };
  const statusIcon  = { ACTIVE: "🟢", UPCOMING: "🔵", COMPLETED: "⚫" };
  const courseStatusColor = { ACTIVE: T.accentG, DRAFT: T.accentY, INACTIVE: T.muted };

  if (loading) return <div style={{ padding: 32, textAlign: "center", color: T.muted }}>Loading…</div>;

  return (
    <div className="fade-up">
      <PageHeader title="My Courses"
        subtitle={selected
          ? `${selected.name} — Course Details`
          : `${batches.length} batch${batches.length !== 1 ? "es" : ""} enrolled${directCourses.length > 0 ? ` · ${directCourses.length} direct enrollment${directCourses.length !== 1 ? "s" : ""}` : ""}`}
        actions={selected ? [<Btn size="sm" variant="ghost" onClick={() => setSelected(null)}>← All Batches</Btn>] : []}
      />

      {!selected ? (
        // ── Batch list view + Direct enrollments ────────────────────────────
        <>
          {/* Batch courses */}
          {batches.length === 0 && directCourses.length === 0 ? (
            <Card>
              <div style={{ padding: 40, textAlign: "center", color: T.muted }}>
                <div style={{ fontSize: 48, marginBottom: 12 }}>📭</div>
                <div style={{ fontFamily: "Syne", fontWeight: 700, fontSize: 16 }}>Not enrolled in any course yet</div>
                <div style={{ fontSize: 13, marginTop: 6 }}>Ask your admin to add you to a batch or enroll you in a course.</div>
              </div>
            </Card>
          ) : (
            <>
              {/* ── Batch-linked courses ── */}
              {batches.length > 0 && (
                <>
                  <div style={{ fontSize: 11, fontWeight: 700, color: T.muted, textTransform: "uppercase", letterSpacing: 1, marginBottom: 10 }}>
                    🏫 Batch Enrollments ({batches.length})
                  </div>
                  <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(300px, 1fr))", gap: 20, marginBottom: 28 }}>
                    {batches.map(b => (
                      <Card key={b.id} style={{ padding: 0, overflow: "hidden", cursor: b.course ? "pointer" : "default" }}
                        onClick={() => b.course && setSelected(b)}>
                        <div style={{ height: 6, background: `linear-gradient(90deg, ${statusColor[b.status] || T.primary}, ${T.accent})` }} />
                        <div style={{ padding: 20 }}>
                          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 12 }}>
                            <div>
                              <div style={{ fontFamily: "Syne", fontWeight: 800, fontSize: 15 }}>{b.name}</div>
                              <div style={{ fontSize: 12, color: T.muted, marginTop: 2 }}>🏢 {b.department || "—"}</div>
                            </div>
                            <span style={{ fontSize: 11, background: `${statusColor[b.status] || T.primary}18`,
                              color: statusColor[b.status] || T.primary, borderRadius: 50, padding: "3px 10px", fontWeight: 700 }}>
                              {statusIcon[b.status]} {b.status}
                            </span>
                          </div>
                          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 8, marginBottom: 14 }}>
                            {[["📅 Start", b.startDate], ["🏁 End", b.endDate]].map(([l, v]) => (
                              <div key={l} style={{ background: T.bg3, borderRadius: 8, padding: "8px 10px" }}>
                                <div style={{ fontSize: 10, color: T.muted }}>{l}</div>
                                <div style={{ fontSize: 12, fontWeight: 700, marginTop: 2 }}>{v || "—"}</div>
                              </div>
                            ))}
                          </div>
                          {b.course ? (
                            <div style={{ background: `${T.primary}10`, border: `1px solid ${T.primary}30`, borderRadius: 10, padding: "12px 14px" }}>
                              <div style={{ display: "flex", gap: 10, alignItems: "center" }}>
                                <div style={{ fontSize: 24 }}>📚</div>
                                <div style={{ flex: 1 }}>
                                  <div style={{ fontWeight: 700, fontSize: 13 }}>{b.course.title}</div>
                                  <div style={{ fontSize: 11, color: T.muted }}>
                                    👨‍🏫 {b.course.teacherName || "Unassigned"}
                                    {b.course.durationHours ? ` · ${b.course.durationHours}h` : ""}
                                  </div>
                                </div>
                                <span style={{ fontSize: 10, background: `${courseStatusColor[b.course.status]}18`,
                                  color: courseStatusColor[b.course.status], borderRadius: 50, padding: "2px 8px", fontWeight: 700 }}>
                                  {b.course.status}
                                </span>
                              </div>
                              <Btn size="xs" variant="primary" full style={{ marginTop: 10 }}>View Course Details →</Btn>
                            </div>
                          ) : (
                            <div style={{ background: T.bg3, borderRadius: 10, padding: "12px 14px", textAlign: "center", color: T.muted, fontSize: 13 }}>
                              📭 No course assigned to this batch yet
                            </div>
                          )}
                        </div>
                      </Card>
                    ))}
                  </div>
                </>
              )}

              {/* ── Directly enrolled courses (no batch) ── */}
              {directCourses.length > 0 && (
                <>
                  <div style={{ fontSize: 11, fontWeight: 700, color: T.muted, textTransform: "uppercase", letterSpacing: 1, marginBottom: 10 }}>
                    📚 Direct Enrollments ({directCourses.length})
                  </div>
                  <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(300px, 1fr))", gap: 20 }}>
                    {directCourses.map(c => (
                      <Card key={c.id} style={{ padding: 0, overflow: "hidden" }}>
                        <div style={{ height: 6, background: `linear-gradient(90deg, ${T.accent}, ${T.primary})` }} />
                        <div style={{ padding: 20 }}>
                          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 10 }}>
                            <div>
                              <div style={{ fontFamily: "Syne", fontWeight: 800, fontSize: 15 }}>{c.title}</div>
                              <div style={{ fontSize: 12, color: T.muted, marginTop: 2 }}>🏢 {c.department || "—"}</div>
                            </div>
                            <span style={{ fontSize: 10, background: `${courseStatusColor[c.status] || T.primary}18`,
                              color: courseStatusColor[c.status] || T.primary, borderRadius: 50, padding: "3px 10px", fontWeight: 700 }}>
                              {c.status || "DRAFT"}
                            </span>
                          </div>
                          <div style={{ background: `${T.accent}10`, border: `1px solid ${T.accent}30`, borderRadius: 10, padding: "10px 14px" }}>
                            <div style={{ fontSize: 12, color: T.muted, marginBottom: 4 }}>
                              👨‍🏫 {c.teacher?.name || "Unassigned"}
                              {c.durationHours ? ` · ${c.durationHours}h` : ""}
                            </div>
                            {c.description && <div style={{ fontSize: 12, color: T.muted }}>{c.description}</div>}
                            <div style={{ marginTop: 8 }}>
                              <span style={{ fontSize: 10, background: `${T.accentG}15`, color: T.accentG,
                                borderRadius: 50, padding: "2px 10px", fontWeight: 700 }}>✅ Directly Enrolled</span>
                            </div>
                          </div>
                        </div>
                      </Card>
                    ))}
                  </div>
                </>
              )}
            </>
          )}
        </>
      ) : (
        // ── Course detail view ───────────────────────────────────────────────
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 20 }}>
          {/* Course info */}
          <Card style={{ padding: 0, overflow: "hidden" }}>
            <div style={{ height: 140, background: `linear-gradient(135deg, ${T.bg3}, ${T.primary}30)`,
              display: "flex", alignItems: "center", justifyContent: "center", fontSize: 64 }}>📚</div>
            <div style={{ padding: 20 }}>
              <div style={{ fontFamily: "Syne", fontWeight: 800, fontSize: 18, marginBottom: 6 }}>
                {selected.course.title}
              </div>
              <div style={{ display: "flex", gap: 8, marginBottom: 12, flexWrap: "wrap" }}>
                <span style={{ fontSize: 11, background: `${courseStatusColor[selected.course.status]}18`,
                  color: courseStatusColor[selected.course.status], borderRadius: 50, padding: "3px 10px", fontWeight: 700 }}>
                  {selected.course.status}
                </span>
                <span style={{ fontSize: 11, background: `${T.accent}18`, color: T.accent,
                  borderRadius: 50, padding: "3px 10px", fontWeight: 700 }}>
                  🏢 {selected.course.department || selected.department || "—"}
                </span>
              </div>
              {selected.course.description && (
                <div style={{ fontSize: 13, color: T.muted, lineHeight: 1.6, marginBottom: 14 }}>
                  {selected.course.description}
                </div>
              )}
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10 }}>
                {[
                  ["👨‍🏫 Teacher",   selected.course.teacherName || "Unassigned"],
                  ["⏱ Duration",    selected.course.durationHours ? `${selected.course.durationHours} hours` : "—"],
                ].map(([l, v]) => (
                  <div key={l} style={{ background: T.bg3, borderRadius: 9, padding: "10px 14px" }}>
                    <div style={{ fontSize: 11, color: T.muted }}>{l}</div>
                    <div style={{ fontSize: 13, fontWeight: 700, marginTop: 3 }}>{v}</div>
                  </div>
                ))}
              </div>
            </div>
          </Card>

          {/* Batch info */}
          <Card style={{ padding: 24 }}>
            <div style={{ fontFamily: "Syne", fontWeight: 700, fontSize: 15, marginBottom: 16 }}>
              🏫 Batch Details
            </div>
            <div style={{ display: "grid", gap: 10 }}>
              {[
                ["Batch Name",   selected.name],
                ["Department",   selected.department || "—"],
                ["Start Date",   selected.startDate || "—"],
                ["End Date",     selected.endDate   || "—"],
                ["Status",       selected.status],
              ].map(([l, v]) => (
                <div key={l} style={{ display: "flex", justifyContent: "space-between",
                  fontSize: 13, padding: "8px 0", borderBottom: `1px solid rgba(45,33,96,.3)` }}>
                  <span style={{ color: T.muted }}>{l}</span>
                  <span style={{ fontWeight: 700, color: l === "Status" ? (statusColor[v] || T.text) : T.text }}>{v}</span>
                </div>
              ))}
            </div>
            <div style={{ marginTop: 20, background: `${T.accentG}10`, border: `1px solid ${T.accentG}30`,
              borderRadius: 10, padding: "14px 16px", fontSize: 13 }}>
              ✅ You are enrolled in this batch. Course content and assignments are managed by your teacher.
            </div>
          </Card>
        </div>
      )}
    </div>
  );
};

// ─── STUDENT TASKS ────────────────────────────────────────────────────────────
// ─── STUDENT LEARNING BOARD ───────────────────────────────────────────────────
export const StudentLearningBoard = () => {
  const [courses, setCourses]   = useState([]);
  const [selected, setSelected] = useState(null); // selected course
  const [materials, setMaterials] = useState([]);
  const [tab, setTab]           = useState("ALL"); // ALL | NOTE | VIDEO | LIVE
  const [loading, setLoading]   = useState(false);
  const [viewNote, setViewNote] = useState(null);

  // Load enrolled courses (via batches)
  useEffect(() => {
    const { getStudentBatches } = require("../../api/auth");
    getStudentBatches()
      .then(d => {
        const list = (Array.isArray(d) ? d : [])
          .filter(b => b.course)
          .map(b => ({ ...b.course, batchName: b.name, batchStatus: b.status }));
        // deduplicate by course id
        const seen = new Set();
        setCourses(list.filter(c => seen.has(c.id) ? false : seen.add(c.id)));
      })
      .catch(console.error);
  }, []);

  const openCourse = (course) => {
    setSelected(course);
    setTab("ALL");
    setLoading(true);
    const { getStudentMaterials } = require("../../api/auth");
    getStudentMaterials(course.id)
      .then(d => setMaterials(Array.isArray(d) ? d : []))
      .catch(console.error)
      .finally(() => setLoading(false));
  };

  const typeIcon  = { NOTE: "📝", VIDEO: "🎥", MEET_LINK: "🔗" };
  const typeColor = { NOTE: T.accent, VIDEO: T.primaryL, MEET_LINK: T.accentG };

  const filtered = tab === "ALL" ? materials
    : tab === "LIVE" ? materials.filter(m => m.type === "MEET_LINK")
    : materials.filter(m => m.type === tab);

  const getYouTubeId = (url = "") => {
    const m = url.match(/(?:youtube\.com\/watch\?v=|youtu\.be\/)([^&\s]+)/);
    return m ? m[1] : null;
  };

  // ── Course list ──────────────────────────────────────────────────────────
  if (!selected) return (
    <div className="fade-up">
      <PageHeader title="Learning Board" subtitle="Select a course to view its materials" />
      {courses.length === 0 ? (
        <Card><div style={{ padding: 40, textAlign: "center", color: T.muted }}>
          <div style={{ fontSize: 40, marginBottom: 10 }}>📭</div>
          <div style={{ fontFamily: "Syne", fontWeight: 700 }}>Not enrolled in any course yet</div>
          <div style={{ fontSize: 13, marginTop: 6 }}>Ask your admin to add you to a batch.</div>
        </div></Card>
      ) : (
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(280px, 1fr))", gap: 18 }}>
          {courses.map(c => (
            <Card key={c.id} style={{ padding: 0, overflow: "hidden" }}>
              <div style={{ height: 5, background: `linear-gradient(90deg, ${T.primary}, ${T.accent})` }} />
              <div style={{ padding: 20 }}>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: 10 }}>
                  <div style={{ fontFamily: "Syne", fontWeight: 800, fontSize: 15 }}>{c.title}</div>
                  <span style={{ fontSize: 10, background: `${T.accentG}15`, color: T.accentG,
                    borderRadius: 50, padding: "2px 8px", fontWeight: 700, flexShrink: 0, marginLeft: 8 }}>
                    {c.batchStatus}
                  </span>
                </div>
                <div style={{ fontSize: 12, color: T.muted, marginBottom: 14 }}>
                  🏢 {c.department || "—"} · 🏫 {c.batchName}
                </div>
                <div style={{ display: "flex", gap: 8, marginBottom: 12 }}>
                  {[["📝", "Notes"], ["🎥", "Videos"], ["🔗", "Live Classes"]].map(([icon, lbl]) => (
                    <div key={lbl} style={{ flex: 1, background: T.bg3, borderRadius: 8,
                      padding: "8px 0", textAlign: "center" }}>
                      <div style={{ fontSize: 18 }}>{icon}</div>
                      <div style={{ fontSize: 10, color: T.muted, marginTop: 3 }}>{lbl}</div>
                    </div>
                  ))}
                </div>
                <Btn size="xs" variant="primary" full onClick={() => openCourse(c)}>Open Learning Board →</Btn>
              </div>
            </Card>
          ))}
        </div>
      )}
    </div>
  );

  // ── Course material view ─────────────────────────────────────────────────
  return (
    <div className="fade-up">
      <PageHeader
        title={selected.title}
        subtitle={`🏫 ${selected.batchName} · 🏢 ${selected.department || "—"}`}
        actions={[<Btn size="sm" variant="ghost" onClick={() => setSelected(null)}>← All Courses</Btn>]}
      />

      {/* Tabs */}
      <div style={{ display: "flex", gap: 8, marginBottom: 20, flexWrap: "wrap" }}>
        {[
          { key: "ALL",   label: `📚 All (${materials.length})` },
          { key: "NOTE",  label: `📝 Notes (${materials.filter(m => m.type === "NOTE").length})` },
          { key: "VIDEO", label: `🎥 Videos (${materials.filter(m => m.type === "VIDEO").length})` },
          { key: "LIVE",  label: `🔗 Live Classes (${materials.filter(m => m.type === "MEET_LINK").length})` },
        ].map(t => (
          <button key={t.key} onClick={() => setTab(t.key)}
            style={{ padding: "7px 18px", borderRadius: 50,
              border: `1.5px solid ${tab === t.key ? T.primary : T.border}`,
              background: tab === t.key ? `${T.primary}20` : "transparent",
              color: tab === t.key ? T.primary : T.muted,
              fontWeight: 700, fontSize: 12, cursor: "pointer" }}>
            {t.label}
          </button>
        ))}
      </div>

      {loading ? (
        <div style={{ padding: 40, textAlign: "center", color: T.muted }}>Loading…</div>
      ) : filtered.length === 0 ? (
        <Card><div style={{ padding: 40, textAlign: "center", color: T.muted }}>
          <div style={{ fontSize: 36, marginBottom: 8 }}>📭</div>
          <div>No {tab === "ALL" ? "materials" : tab === "NOTE" ? "notes" : tab === "VIDEO" ? "videos" : "live classes"} available yet.</div>
          <div style={{ fontSize: 12, marginTop: 6 }}>Your teacher hasn\'t uploaded anything here yet.</div>
        </div></Card>
      ) : (
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(320px, 1fr))", gap: 18 }}>
          {filtered.map(m => {
            const ytId = m.type === "VIDEO" ? getYouTubeId(m.content || "") : null;
            const dColor = m.type === "MEET_LINK" ? T.accentG : typeColor[m.type];
            const dIcon  = m.type === "MEET_LINK" ? "🔗" : typeIcon[m.type];

            // Detect live platform
            const platform = m.type === "MEET_LINK"
              ? (m.content?.includes("zoom") ? "Zoom 🟦" : m.content?.includes("teams") ? "Teams 🟣" : "Google Meet 🟢")
              : "";

            return (
              <Card key={m.id} style={{ padding: 0, overflow: "hidden" }}>
                <div style={{ height: 5, background: `linear-gradient(90deg, ${dColor}, ${T.primary})` }} />

                {/* YouTube embed */}
                {ytId && (
                  <div style={{ width: "100%", aspectRatio: "16/9", background: "#000" }}>
                    <iframe src={`https://www.youtube.com/embed/${ytId}`}
                      style={{ width: "100%", height: "100%", border: "none" }}
                      allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
                      allowFullScreen title={m.title} />
                  </div>
                )}

                <div style={{ padding: 16 }}>
                  {/* Header */}
                  <div style={{ display: "flex", gap: 10, alignItems: "flex-start", marginBottom: 10 }}>
                    <div style={{ width: 38, height: 38, borderRadius: 10, background: `${dColor}20`,
                      display: "flex", alignItems: "center", justifyContent: "center", fontSize: 20, flexShrink: 0 }}>
                      {dIcon}
                    </div>
                    <div style={{ flex: 1 }}>
                      <div style={{ fontWeight: 800, fontSize: 14, fontFamily: "Syne" }}>{m.title}</div>
                      <div style={{ fontSize: 11, color: T.muted, marginTop: 2 }}>
                        👨‍🏫 {m.uploadedBy?.name || "Teacher"} · {new Date(m.createdAt).toLocaleDateString("en-IN")}
                      </div>
                    </div>
                  </div>

                  {m.description && (
                    <div style={{ fontSize: 12, color: T.muted, marginBottom: 10 }}>{m.description}</div>
                  )}

                  {/* NOTE — file download or plain text */}
                  {m.type === "NOTE" && (() => {
                    const isFile = m.content?.startsWith("data:");
                    if (isFile) {
                      const mimeMatch = m.content.match(/^data:([^;]+);/);
                      const mime = mimeMatch?.[1] || "";
                      const ext = mime.includes("pdf") ? "pdf" : mime.includes("word") ? "docx" :
                                  mime.includes("sheet") ? "xlsx" : mime.includes("presentation") ? "pptx" : "txt";
                      const icon = mime.includes("pdf") ? "📕" : mime.includes("word") ? "📘" :
                                   mime.includes("sheet") ? "📗" : mime.includes("presentation") ? "📙" : "📄";
                      return (
                        <div style={{ background: `${T.accent}10`, border: `1px solid ${T.accent}30`,
                          borderRadius: 10, padding: "14px 16px" }}>
                          <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 10 }}>
                            <span style={{ fontSize: 32 }}>{icon}</span>
                            <div>
                              <div style={{ fontWeight: 700, fontSize: 13 }}>{m.title}.{ext}</div>
                              <div style={{ fontSize: 11, color: T.muted, marginTop: 2 }}>
                                {ext.toUpperCase()} Document · Click to download
                              </div>
                            </div>
                          </div>
                          <a href={m.content} download={`${m.title}.${ext}`}
                            style={{ display: "block", textAlign: "center", background: T.accent,
                              color: "#fff", borderRadius: 8, padding: "9px 0",
                              fontWeight: 700, fontSize: 13, textDecoration: "none" }}>
                            ⬇ Download {ext.toUpperCase()}
                          </a>
                        </div>
                      );
                    }
                    // Plain text note
                    return (
                      <div>
                        <div style={{ background: T.bg3, borderRadius: 8, padding: "10px 12px",
                          fontSize: 12, color: T.text, maxHeight: 80, overflow: "hidden",
                          whiteSpace: "pre-wrap", marginBottom: 8 }}>
                          {m.content?.substring(0, 200)}{m.content?.length > 200 ? "…" : ""}
                        </div>
                        <Btn size="xs" variant="ghost" onClick={() => setViewNote(m)}>📖 Read Full Note</Btn>
                      </div>
                    );
                  })()}

                  {/* VIDEO — non-YouTube */}
                  {m.type === "VIDEO" && !ytId && (
                    <a href={m.content} target="_blank" rel="noreferrer"
                      style={{ display: "block", background: `${T.primaryL}15`,
                        border: `1px solid ${T.primaryL}30`, borderRadius: 8,
                        padding: "10px 14px", fontSize: 13, color: T.primaryL,
                        textDecoration: "none", fontWeight: 600 }}>
                      🎥 Open Video →
                    </a>
                  )}

                  {/* LIVE CLASS */}
                  {m.type === "MEET_LINK" && (
                    <div style={{ background: `${T.accentG}10`, border: `1px solid ${T.accentG}30`,
                      borderRadius: 8, padding: "12px 14px" }}>
                      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 }}>
                        <span style={{ fontSize: 12, color: T.muted }}>{platform}</span>
                        {m.scheduledAt && (
                          <span style={{ fontSize: 11, color: T.muted }}>
                            📅 {new Date(m.scheduledAt).toLocaleString("en-IN", {
                              weekday: "short", day: "numeric", month: "short",
                              hour: "2-digit", minute: "2-digit" })}
                          </span>
                        )}
                      </div>
                      <a href={m.content} target="_blank" rel="noreferrer"
                        style={{ display: "inline-block", background: T.accentG, color: "#fff",
                          borderRadius: 8, padding: "9px 20px", fontSize: 13,
                          fontWeight: 700, textDecoration: "none", width: "100%",
                          textAlign: "center", boxSizing: "border-box" }}>
                        🔗 Join Live Class →
                      </a>
                    </div>
                  )}
                </div>
              </Card>
            );
          })}
        </div>
      )}

      {/* Full Note Modal */}
      {viewNote && (
        <div onClick={() => setViewNote(null)}
          style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,.75)", zIndex: 9999,
            display: "flex", alignItems: "center", justifyContent: "center", backdropFilter: "blur(6px)" }}>
          <div onClick={e => e.stopPropagation()}
            style={{ background: T.card, border: `1px solid ${T.border}`, borderRadius: 18,
              padding: 32, width: "90%", maxWidth: 700, maxHeight: "85vh",
              overflowY: "auto", position: "relative" }}>
            <button onClick={() => setViewNote(null)}
              style={{ position: "absolute", top: 14, right: 14, width: 30, height: 30,
                border: `1px solid ${T.border}`, borderRadius: "50%", background: T.bg3,
                cursor: "pointer", color: T.muted, fontSize: 16, display: "flex",
                alignItems: "center", justifyContent: "center" }}>✕</button>
            <div style={{ display: "flex", gap: 12, alignItems: "center", marginBottom: 16 }}>
              <span style={{ fontSize: 28 }}>📝</span>
              <div>
                <div style={{ fontFamily: "Syne", fontWeight: 800, fontSize: 20 }}>{viewNote.title}</div>
                <div style={{ fontSize: 12, color: T.muted, marginTop: 2 }}>
                  👨‍🏫 {viewNote.uploadedBy?.name} · {selected.title} · {new Date(viewNote.createdAt).toLocaleDateString("en-IN")}
                </div>
              </div>
            </div>
            <pre style={{ background: T.bg3, borderRadius: 10, padding: 20,
              fontSize: 13, color: T.text, whiteSpace: "pre-wrap",
              fontFamily: "DM Sans, sans-serif", lineHeight: 1.8, margin: 0 }}>
              {viewNote.content}
            </pre>
          </div>
        </div>
      )}
    </div>
  );
};

export const StudentTasks = () => {
  const [assignments, setAssignments] = useState([]);
  const [submissions, setSubmissions] = useState([]);
  const [tab, setTab]                 = useState("Pending");
  const [loading, setLoading]         = useState(true);
  const [submitModal, setSubmitModal] = useState(null);
  const [content, setContent]         = useState("");

  const load = () => {
    Promise.all([getStudentAssignments(), getStudentSubmissions()])
      .then(([a, s]) => { setAssignments(Array.isArray(a) ? a : []); setSubmissions(Array.isArray(s) ? s : []); })
      .catch(console.error).finally(() => setLoading(false));
  };
  useEffect(() => { load(); }, []);

  const submittedIds = new Set(submissions.map(s => s.assignment?.id));
  const pending      = assignments.filter(a => !submittedIds.has(a.id));
  const submitted    = submissions.filter(s => s.status !== "GRADED");
  const graded       = submissions.filter(s => s.status === "GRADED");

  const handleSubmit = async () => {
    if (!content.trim()) { alert("Please write your answer before submitting."); return; }
    try {
      const { submitAssignment } = await import("../../api/auth");
      await submitAssignment(submitModal.id, { content });
      alert("Assignment submitted!");
      setSubmitModal(null); setContent(""); load();
    } catch (err) { alert("Failed: " + err.message); }
  };

  const fmt = dt => dt ? new Date(dt).toLocaleString("en-IN", { dateStyle: "medium", timeStyle: "short" }) : "—";

  return (
    <div className="fade-up">
      <PageHeader title="Tasks & Assignments" />
      <Tabs tabs={[`Pending (${pending.length})`, `Submitted (${submitted.length})`, `Graded (${graded.length})`]} active={tab} onChange={setTab} />
      <Card>
        {loading ? <div style={{ padding: 32, textAlign: "center", color: T.muted }}>Loading…</div> : (
          <>
            {tab.startsWith("Pending") && (pending.length === 0
              ? <div style={{ padding: 24, textAlign: "center", color: T.muted }}>🎉 No pending assignments!</div>
              : pending.map(a => {
                  const overdue = a.dueDate && new Date(a.dueDate) < new Date();
                  return (
                    <div key={a.id} style={{ display: "flex", gap: 14, padding: "14px 0", borderBottom: `1px solid rgba(45,33,96,.4)`, alignItems: "center" }}>
                      <div style={{ fontSize: 28, flexShrink: 0 }}>📝</div>
                      <div style={{ flex: 1 }}>
                        <div style={{ fontSize: 14, fontWeight: 700 }}>{a.title}</div>
                        <div style={{ fontSize: 12, color: T.muted }}>{a.course?.title} · Max: {a.maxMarks} marks</div>
                        <div style={{ fontSize: 11, color: overdue ? T.accentR : T.muted }}>Due: {fmt(a.dueDate)}</div>
                      </div>
                      <Badge type={overdue ? "danger" : "warning"}>{overdue ? "Overdue" : "Pending"}</Badge>
                      <Btn size="sm" variant="primary" onClick={() => setSubmitModal(a)}>Submit →</Btn>
                    </div>
                  );
                })
            )}
            {tab.startsWith("Submitted") && (submitted.length === 0
              ? <div style={{ padding: 24, textAlign: "center", color: T.muted }}>No submissions yet.</div>
              : submitted.map(s => (
                <div key={s.id} style={{ display: "flex", gap: 14, padding: "14px 0", borderBottom: `1px solid rgba(45,33,96,.4)`, alignItems: "center" }}>
                  <div style={{ fontSize: 28 }}>📋</div>
                  <div style={{ flex: 1 }}>
                    <div style={{ fontSize: 14, fontWeight: 700 }}>{s.assignment?.title}</div>
                    <div style={{ fontSize: 12, color: T.muted }}>Submitted: {fmt(s.submittedAt)}</div>
                  </div>
                  <Badge type="info">Awaiting Grade</Badge>
                </div>
              ))
            )}
            {tab.startsWith("Graded") && (graded.length === 0
              ? <div style={{ padding: 24, textAlign: "center", color: T.muted }}>No graded assignments yet.</div>
              : graded.map(s => (
                <div key={s.id} style={{ display: "flex", gap: 14, padding: "14px 0", borderBottom: `1px solid rgba(45,33,96,.4)`, alignItems: "center" }}>
                  <div style={{ fontSize: 28 }}>🏅</div>
                  <div style={{ flex: 1 }}>
                    <div style={{ fontSize: 14, fontWeight: 700 }}>{s.assignment?.title}</div>
                    <div style={{ fontSize: 12, color: T.muted }}>{s.teacherFeedback || "No feedback"}</div>
                  </div>
                  <div style={{ fontFamily: "Syne", fontWeight: 900, fontSize: 18, color: T.accentG }}>{s.marksObtained}/{s.assignment?.maxMarks || 100}</div>
                  <Badge type="success">Graded</Badge>
                </div>
              ))
            )}
          </>
        )}
      </Card>
      <Modal open={!!submitModal} onClose={() => setSubmitModal(null)} title={`Submit: ${submitModal?.title}`}>
        <div style={{ fontSize: 13, color: T.muted, marginBottom: 14 }}>
          Course: <strong>{submitModal?.course?.title}</strong> · Max marks: <strong>{submitModal?.maxMarks}</strong>
        </div>
        {submitModal?.description && (
          <div style={{ background: T.bg3, borderRadius: 9, padding: 12, fontSize: 13, marginBottom: 14, color: T.muted }}>{submitModal.description}</div>
        )}
        <div style={{ marginBottom: 14 }}>
          <label style={{ fontSize: 11, fontWeight: 700, color: T.muted, textTransform: "uppercase", letterSpacing: 1, display: "block", marginBottom: 6 }}>Your Answer / Notes *</label>
          <textarea rows={5} value={content} onChange={e => setContent(e.target.value)}
            placeholder="Write your answer here…"
            style={{ width: "100%", background: T.bg3, border: `1.5px solid ${T.border}`, borderRadius: 9, padding: "10px 14px", fontSize: 13, color: T.text, outline: "none", resize: "vertical", fontFamily: "DM Sans" }}
            onFocus={e => e.target.style.borderColor = T.primary}
            onBlur={e => e.target.style.borderColor = T.border}
          />
        </div>
        <Btn variant="primary" full size="lg" onClick={handleSubmit}>Submit Assignment →</Btn>
      </Modal>
    </div>
  );
};

// ─── STUDENT FEES ─────────────────────────────────────────────────────────────
export const StudentFees = () => {
  const [fees, setFees]       = useState([]);
  const [loading, setLoading] = useState(true);
  const [tab, setTab]         = useState("All");

  useEffect(() => {
    getStudentFees().then(d => setFees(Array.isArray(d) ? d : []))
      .catch(console.error).finally(() => setLoading(false));
  }, []);

  // Split: batch fees (auto-generated) vs variable fees (manually added by admin)
  const batchFees    = fees.filter(f => f.batch);
  const variableFees = fees.filter(f => !f.batch);

  const byTab = tab === "Pending" ? fees.filter(f => f.status === "PENDING")
              : tab === "Overdue" ? fees.filter(f => f.status === "OVERDUE")
              : tab === "Paid"    ? fees.filter(f => f.status === "PAID")
              : tab === "Batch"   ? batchFees
              : tab === "Other"   ? variableFees
              : fees;

  const total   = fees.reduce((s, f) => s + Number(f.amount || 0), 0);
  const paid    = fees.filter(f => f.status === "PAID").reduce((s, f) => s + Number(f.paidAmount || f.amount || 0), 0);
  const pending = total - paid;
  const rate    = total > 0 ? Math.round((paid / total) * 100) : 0;

  const feeIcon = t => ({ TUITION: "📚", EXAM: "📝", LAB: "🧪", LIBRARY: "📖", TRANSPORT: "🚌" }[t] || "💳");

  const FeeRow = ({ f }) => (
    <div style={{ padding: "14px 0", borderBottom: `1px solid rgba(45,33,96,.4)` }}>
      <div style={{ display: "flex", gap: 14, alignItems: "center" }}>
        <div style={{ width: 42, height: 42, borderRadius: 10, flexShrink: 0,
          background: f.batch ? `${T.primary}15` : `${T.accentY}15`,
          display: "flex", alignItems: "center", justifyContent: "center", fontSize: 20 }}>
          {feeIcon(f.feeType)}
        </div>
        <div style={{ flex: 1 }}>
          <div style={{ fontSize: 14, fontWeight: 700 }}>{f.description || f.feeType || "Fee"}</div>
          <div style={{ display: "flex", gap: 6, flexWrap: "wrap", marginTop: 4 }}>
            {/* Batch fee tag */}
            {f.batch ? (
              <span style={{ fontSize: 10, background: `${T.primary}18`, color: T.primaryL,
                borderRadius: 50, padding: "2px 10px", fontWeight: 700 }}>
                🏫 Batch: {f.batch.name}
              </span>
            ) : (
              <span style={{ fontSize: 10, background: `${T.accentY}18`, color: T.accentY,
                borderRadius: 50, padding: "2px 10px", fontWeight: 700 }}>
                💼 Variable Fee
              </span>
            )}
            {f.course?.title && (
              <span style={{ fontSize: 10, background: `${T.accentG}18`, color: T.accentG,
                borderRadius: 50, padding: "2px 8px", fontWeight: 700 }}>
                📚 {f.course.title}
              </span>
            )}
            {f.feeType && (
              <span style={{ fontSize: 10, background: `${T.accent}15`, color: T.accent,
                borderRadius: 50, padding: "2px 8px", fontWeight: 700 }}>
                {f.feeType}
              </span>
            )}
          </div>
          <div style={{ fontSize: 11, color: T.muted, marginTop: 4 }}>
            📅 Due: {f.dueDate || "—"}
            {f.paidDate && <span style={{ color: T.accentG }}> · ✅ Paid: {f.paidDate}</span>}
          </div>
        </div>
        <div style={{ textAlign: "right", flexShrink: 0 }}>
          <div style={{ fontFamily: "Syne", fontWeight: 900, fontSize: 16,
            color: f.status === "PAID" ? T.accentG : f.status === "OVERDUE" ? T.accentR : T.accent }}>
            ₹{Number(f.amount).toLocaleString("en-IN")}
          </div>
          <Badge type={f.status === "PAID" ? "success" : f.status === "OVERDUE" ? "danger" : "warning"}>
            {f.status}
          </Badge>
        </div>
      </div>
      {/* Read-only notice */}
      {f.status !== "PAID" && (
        <div style={{ fontSize: 11, color: T.muted, marginTop: 8, paddingLeft: 56,
          display: "flex", alignItems: "center", gap: 6 }}>
          ℹ️ Contact your admin or parent to process payment.
        </div>
      )}
    </div>
  );

  return (
    <div className="fade-up">
      <PageHeader title="My Fees" subtitle="Your fee records — read only. Contact admin for payments." />

      <div style={{ display: "grid", gridTemplateColumns: "repeat(4,1fr)", gap: 18, marginBottom: 24 }}>
        <StatCard icon="💰" label="Total Billed"   value={`₹${total.toLocaleString("en-IN")}`}   color={T.text}    />
        <StatCard icon="✅" label="Paid"            value={`₹${paid.toLocaleString("en-IN")}`}    color={T.accentG} />
        <StatCard icon="⚠️" label="Outstanding"    value={`₹${pending.toLocaleString("en-IN")}`} color={T.accentR} />
        <StatCard icon="📊" label="Payment Rate"   value={`${rate}%`}                             color={T.accent}  />
      </div>

      <Tabs tabs={["All", "Pending", "Overdue", "Paid", "Batch", "Other"]} active={tab} onChange={setTab} />

      <div style={{ display: "grid", gridTemplateColumns: "2fr 1fr", gap: 20 }}>
        <Card>
          {loading
            ? <div style={{ padding: 32, textAlign: "center", color: T.muted }}>Loading…</div>
            : byTab.length === 0
              ? <div style={{ padding: 32, textAlign: "center", color: T.muted }}>
                  No {tab === "All" ? "" : tab.toLowerCase()} fees found.
                </div>
              : byTab.map(f => <FeeRow key={f.id} f={f} />)
          }
        </Card>

        <div>
          {/* Summary card */}
          <Card style={{ padding: 24, marginBottom: 16 }}>
            <div style={{ fontFamily: "Syne", fontWeight: 700, marginBottom: 14 }}>Summary</div>
            {[["Total Billed", `₹${total.toLocaleString("en-IN")}`, T.text],
              ["Paid",         `₹${paid.toLocaleString("en-IN")}`,    T.accentG],
              ["Outstanding",  `₹${pending.toLocaleString("en-IN")}`, T.accentR]
            ].map(([l, v, col]) => (
              <div key={l} style={{ display: "flex", justifyContent: "space-between",
                fontSize: 13, padding: "8px 0", borderBottom: `1px solid rgba(45,33,96,.4)` }}>
                <span style={{ color: T.muted }}>{l}</span>
                <span style={{ fontFamily: "Syne", fontWeight: 800, color: col }}>{v}</span>
              </div>
            ))}
            <div style={{ marginTop: 14 }}>
              <ProgressBar value={rate} color={T.accentG} height={8} />
              <div style={{ fontSize: 11, color: T.muted, marginTop: 6 }}>Payment rate: {rate}%</div>
            </div>
          </Card>

          {/* Fee type breakdown */}
          <Card style={{ padding: 24 }}>
            <div style={{ fontFamily: "Syne", fontWeight: 700, marginBottom: 14 }}>Fee Types</div>
            <div style={{ padding: "10px 14px", borderRadius: 9, marginBottom: 8,
              background: `${T.primary}10`, border: `1px solid ${T.primary}25` }}>
              <div style={{ fontSize: 12, fontWeight: 700, color: T.primaryL }}>🏫 Batch Fees</div>
              <div style={{ fontSize: 11, color: T.muted, marginTop: 3 }}>
                {batchFees.length} fee record{batchFees.length !== 1 ? "s" : ""} auto-generated by admin
              </div>
            </div>
            <div style={{ padding: "10px 14px", borderRadius: 9,
              background: `${T.accentY}10`, border: `1px solid ${T.accentY}25` }}>
              <div style={{ fontSize: 12, fontWeight: 700, color: T.accentY }}>💼 Variable Fees</div>
              <div style={{ fontSize: 11, color: T.muted, marginTop: 3 }}>
                {variableFees.length} manually assigned fee record{variableFees.length !== 1 ? "s" : ""}
              </div>
            </div>
          </Card>
        </div>
      </div>
    </div>
  );
};

// ─── STUDENT NOTIFICATIONS ────────────────────────────────────────────────────
export const StudentNotifications = () => {
  const [notifs, setNotifs]   = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter]   = useState("ALL");

  useEffect(() => {
    getStudentNotifications()
      .then(d => setNotifs(Array.isArray(d) ? d : []))
      .catch(console.error)
      .finally(() => setLoading(false));
  }, []);

  const handleMarkRead = async id => {
    await markStudentNotifRead(id).catch(console.error);
    setNotifs(n => n.map(x => x.id === id ? { ...x, read: true } : x));
  };
  const handleMarkAll = async () => {
    await markStudentNotifReadAll().catch(console.error);
    setNotifs(n => n.map(x => ({ ...x, read: true })));
  };

  const typeIcon  = { INFO: "ℹ️", WARNING: "⚠️", SUCCESS: "✅", ERROR: "❌" };
  const typeColor = { INFO: T.accent, WARNING: T.accentY, SUCCESS: T.accentG, ERROR: "#ef4444" };
  const unreadCount = notifs.filter(n => !n.read).length;
  const filtered = filter === "ALL" ? notifs
    : filter === "UNREAD" ? notifs.filter(n => !n.read)
    : notifs.filter(n => n.type === filter);

  return (
    <div className="fade-up">
      <PageHeader title="Notifications"
        subtitle={`${unreadCount} unread · ${notifs.length} total`}
        actions={[<Btn variant="ghost" size="sm" onClick={handleMarkAll} disabled={unreadCount === 0}>✓ Mark All Read</Btn>]} />

      <div style={{ display: "flex", gap: 8, marginBottom: 16, flexWrap: "wrap" }}>
        {[
          { key: "ALL",     label: `All (${notifs.length})` },
          { key: "UNREAD",  label: `🔵 Unread (${unreadCount})` },
          { key: "INFO",    label: "ℹ️ Info" },
          { key: "WARNING", label: "⚠️ Fees/Alerts" },
          { key: "SUCCESS", label: "✅ Success" },
        ].map(f => (
          <button key={f.key} onClick={() => setFilter(f.key)}
            style={{ padding: "6px 14px", borderRadius: 50, cursor: "pointer",
              border: `1.5px solid ${filter === f.key ? T.primary : T.border}`,
              background: filter === f.key ? `${T.primary}20` : "transparent",
              color: filter === f.key ? T.primary : T.muted, fontWeight: 600, fontSize: 12 }}>
            {f.label}
          </button>
        ))}
      </div>

      <Card>
        {loading ? <div style={{ padding: 32, textAlign: "center", color: T.muted }}>Loading…</div>
        : filtered.length === 0 ? (
          <div style={{ padding: 40, textAlign: "center", color: T.muted }}>
            <div style={{ fontSize: 40, marginBottom: 10 }}>🔔</div>
            <div style={{ fontFamily: "Syne", fontWeight: 700 }}>No notifications</div>
          </div>
        ) : filtered.map((n, i) => (
          <div key={n.id} onClick={() => !n.read && handleMarkRead(n.id)}
            style={{ display: "flex", gap: 14, padding: "14px 0",
              borderBottom: i < filtered.length - 1 ? `1px solid rgba(45,33,96,.3)` : "none",
              alignItems: "flex-start", cursor: !n.read ? "pointer" : "default",
              background: !n.read ? `${T.primary}05` : "transparent" }}>
            <div style={{ width: 40, height: 40, borderRadius: 10, flexShrink: 0,
              background: `${typeColor[n.type] || T.primary}18`,
              display: "flex", alignItems: "center", justifyContent: "center", fontSize: 20 }}>
              {typeIcon[n.type] || "🔔"}
            </div>
            <div style={{ flex: 1, minWidth: 0 }}>
              <div style={{ fontSize: 14, fontWeight: n.read ? 500 : 700 }}>{n.title}</div>
              <div style={{ fontSize: 12, color: T.muted, marginTop: 3, lineHeight: 1.5 }}>{n.message}</div>
              <div style={{ fontSize: 11, color: T.muted, marginTop: 5 }}>
                {n.createdAt ? new Date(n.createdAt).toLocaleString("en-IN", {
                  day: "numeric", month: "short", hour: "2-digit", minute: "2-digit" }) : ""}
              </div>
            </div>
            {!n.read && <div style={{ width: 10, height: 10, borderRadius: "50%",
              background: typeColor[n.type] || T.primaryL, flexShrink: 0, marginTop: 6 }} />}
          </div>
        ))}
      </Card>
    </div>
  );
};

